type Concat<T extends unknown[], U extends unknown[]> = [...T, ...U];

type AB = Concat<[string, number], [boolean, Date]>;
// [string, number, boolean, Date]

function concat<T extends unknown[], U extends unknown[]>(
  a: T,
  b: U
): Concat<T, U> {
  return [...a, ...b] as Concat<T, U>;
}

