import React, { useState, useRef } from 'react';

interface ButtonProps {
  label: string;
  onClick: (count: number) => void;
  disabled?: boolean;
}

const Counter: React.FC<ButtonProps> = ({ label, onClick, disabled = false }) => {
  const [count, setCount] = useState<number>(0);

  const handleClick = (event: React.MouseEvent<HTMLButtonElement>) => {
    const next = count + 1;
    setCount(next);
    onClick(next);
  };

  return (
    <button onClick={handleClick} disabled={disabled}>
      {label}: {count}
    </button>
  );
};

export default Counter;

type Action =
  | { type: 'increment' }
  | { type: 'decrement' }
  | { type: 'reset'; payload: number };

interface State { count: number; }

function reducer(state: State, action: Action): State {
  switch (action.type) {
    case 'increment': return { count: state.count + 1 };
    case 'decrement': return { count: state.count - 1 };
    case 'reset':     return { count: action.payload };
  }
}

// In a component:
const [state, dispatch] = React.useReducer(reducer, { count: 0 });
dispatch({ type: 'reset', payload: 10 });

import { Component, Input, Output, EventEmitter, signal } from '@angular/core';
import { CommonModule } from '@angular/common';

interface Task {
  id: number;
  title: string;
  completed: boolean;
}

@Component({
  selector: 'app-task-item',
  standalone: true,
  imports: [CommonModule],
  template: `
    <li [class.done]="task.completed">
      {{ task.title }}
      <button (click)="toggle.emit(task.id)">Toggle</button>
    </li>
  `
})
export class TaskItemComponent {
  @Input({ required: true }) task!: Task;
  @Output() toggle = new EventEmitter<number>();

  // Angular signals (v17+)
  readonly count = signal<number>(0);
  increment() { this.count.update(v => v + 1); }
}

import { Controller, Get, Post, Body, Param, ParseIntPipe } from '@nestjs/common';

export class CreateUserDto {
  readonly name!: string;
  readonly email!: string;
  readonly age!: number;
}

interface User extends CreateUserDto {
  id: number;
}

@Controller('users')
export class UsersController {
  private users: User[] = [];

  @Post()
  create(@Body() dto: CreateUserDto): User {
    const user: User = { id: Date.now(), ...dto };
    this.users.push(user);
    return user;
  }

  @Get(':id')
  findOne(@Param('id', ParseIntPipe) id: number): User | undefined {
    return this.users.find(u => u.id === id);
  }
}

