// Use unknown instead where possible — forces you to narrow:
function safeTransform(data: unknown): number[] {
  if (!Array.isArray(data)) throw new Error('Expected array');
  return data.map((item) => {
    if (typeof item !== 'object' || item === null) throw new Error();
    return (item as { value: number }).value;
  });
}
